function ExperienceCard({ experience, index }: { experience: typeof experiences[0], index: number }) {
    const mouseX = useMotionValue(0);
    const mouseY = useMotionValue(0);

    const rotateX = useTransform(mouseY, [0, 400], [5, -5]);
    const rotateY = useTransform(mouseX, [0, 600], [-5, 5]);

    function handleMouseMove({ currentTarget, clientX, clientY }: MouseEvent) {
        const { left, top, width, height } = currentTarget.getBoundingClientRect();
        mouseX.set(clientX - left);
        mouseY.set(clientY - top);
    }

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-100px" }}
            transition={{ duration: 0.5, delay: index * 0.1 }}
            onMouseMove={handleMouseMove}
            style={{ rotateX, rotateY, transformStyle: "preserve-3d" }}
            className="group relative rounded-2xl border border-white/10 bg-gray-900/50 px-8 py-10 shadow-2xl overflow-hidden perspective-1000"
        >
            {/* Spotlight Effect */}
            <motion.div
                className="pointer-events-none absolute -inset-px rounded-xl opacity-0 transition duration-300 group-hover:opacity-100"
                style={{
                    background: useMotionTemplate`
            radial-gradient(
              650px circle at ${mouseX}px ${mouseY}px,
              rgba(14, 165, 233, 0.15),
              transparent 80%
            )
          `,
                }}
            />

            <div className="relative z-10 flex flex-col gap-4">
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                    <div>
                        <div className="flex items-center gap-3 mb-2">
                            <div className={`p-2 rounded-lg bg-gradient-to-br ${experience.color} opacity-80`}>
                                <Briefcase className="w-5 h-5 text-white" />
                            </div>
                            <h3 className="text-xl font-bold text-white group-hover:text-accent transition-colors">
                                {experience.role}
                            </h3>
                        </div>
                        <p className="text-lg font-medium text-muted-foreground ml-1">
                            {experience.company}
                        </p>
                    </div>

                    <div className="flex flex-col items-start sm:items-end gap-1 text-sm text-gray-400">
                        <div className="flex items-center gap-2">
                            <Calendar className="w-4 h-4" />
                            {experience.period}
                        </div>
                        <div className="flex items-center gap-2">
                            <MapPin className="w-4 h-4" />
                            {experience.location}
                        </div>
                    </div>
                </div>

                <p className="text-base leading-relaxed text-gray-300 group-hover:text-gray-100 transition-colors">
                    {experience.description}
                </p>

                <div className="flex flex-wrap gap-2 mt-2">
                    {experience.tags.map((tag) => (
                        <span
                            key={tag}
                            className="inline-flex items-center rounded-md bg-white/5 px-3 py-1 text-xs font-medium text-accent ring-1 ring-inset ring-white/10 group-hover:bg-accent/10 group-hover:ring-accent/20 transition-all"
                        >
                            {tag}
                        </span>
                    ))}
                </div>
            </div>
        </motion.div>
    );
}

